mapper.insert:
insert into biz_backpacker_profile (
    user_id, copper_coins, reputation_score, last_checkin_date,
    completed_tasks, failed_tasks, create_time, update_time
) values (
    #{userId}, #{copperCoins}, #{reputationScore}, #{lastCheckinDate},
    #{completedTasks}, #{failedTasks}, #{createTime}, #{updateTime}
)

mapper.update:
update biz_backpacker_profile
set copper_coins = copper_coins - #{amount},
    update_time = sysdate()
where user_id = #{userId}
  and copper_coins >= #{amount}

mapper.insert:
insert into biz_coin_transaction (
    user_id, amount, balance_after, tx_type, ref_id, remark, create_time
) values (
    #{userId}, #{amount}, #{balanceAfter}, #{txType}, #{refId}, #{remark}, #{createTime}
)

mapper.select:
select transaction_id, user_id, amount, balance_after, tx_type, ref_id, remark, create_time
from biz_coin_transaction
where user_id = #{userId}
order by create_time desc
limit #{limit}

select p.user_id, p.copper_coins, p.reputation_score, p.last_checkin_date, p.completed_tasks, p.failed_tasks, p.create_time, p.update_time, u.user_name, u.nick_name, u.phonenumber from biz_backpacker_profile p inner join sys_user u on p.user_id = u.user_id
u.del_flag = '0'
and p.user_id = #{userId}
and u.user_name like concat('%', #{userName}, '%')
and u.nick_name like concat('%', #{nickName}, '%')
and p.reputation_score >= #{params.minReputation}
and p.reputation_score <= #{params.maxReputation}
order by p.update_time desc

select t.transaction_id, t.user_id, t.amount, t.balance_after, t.tx_type, t.ref_id, t.remark, t.create_time, u.user_name, u.nick_name from biz_coin_transaction t inner join sys_user u on t.user_id = u.user_id
and t.user_id = #{userId}
and t.tx_type = #{txType}
and u.user_name like concat('%', #{userName}, '%')
and u.nick_name like concat('%', #{nickName}, '%')
order by t.create_time desc

select l.log_id, l.user_id, l.delta, l.score_after, l.reason, l.ref_id, l.remark, l.create_time, u.user_name, u.nick_name from biz_reputation_log l inner join sys_user u on l.user_id = u.user_id
and l.user_id = #{userId}
and l.reason = #{reason}
and u.user_name like concat('%', #{userName}, '%')
and u.nick_name like concat('%', #{nickName}, '%')
order by l.create_time desc
